import sys

class Solution:
    def postfixToInfix(self, s: str) -> str:
        stack = []
        for token in s.split():
            if token.isalpha() or token.isdigit():
                stack.append(token)
            else:
                operand2 = stack.pop()
                operand1 = stack.pop()
                infix_expression = f'({operand1} {token} {operand2})'
                stack.append(infix_expression)
        return stack[0]

