#include <numeric>
#include <iostream>
#include <stack>
#include <sstream>
using namespace std;

class Solution {
public:
    string postfixToInfix(string s) {
        stack<string> st;
        stringstream ss(s);
        string token;
        while (ss >> token) {
            if (isalpha(token[0]) || isdigit(token[0])) {
                st.push(token);
            } else {
                string operand2 = st.top(); st.pop();
                string operand1 = st.top(); st.pop();
                string infix_expression = '(' + operand1 + ' ' + token + ' ' + operand2 + ')';
                st.push(infix_expression);
            }
        }
        return st.top();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string s;
    getline(cin, s);
    Solution sol;
    string ans = sol.postfixToInfix(s);
    cout << ans << '\n';
    return 0;
}
